#!/usr/bin/env python3
"""Test primer3 installation."""
import subprocess

input_text = """SEQUENCE_ID=example
SEQUENCE_
PRIMER_TASK=generic
PRIMER_PICK_LEFT_PRIMER=1
PRIMER_PICK_RIGHT_PRIMER=1
PRIMER_OPT_SIZE=20
PRIMER_MIN_SIZE=18
PRIMER_MAX_SIZE=25
PRIMER_PRODUCT_SIZE_RANGE=200-400
PRIMER_NUM_RETURN=3
=
"""

result = subprocess.run(['primer3_core'], input=input_text, capture_output=True, text=True)
print("=== PRIMER3 OUTPUT ===")
print(result.stdout)
if result.stderr:
    print("=== STDERR ===")
    print(result.stderr)

